#[derive(Debug, Clone)]
struct CsvTable {
    headers: Vec<String>,
    rows: Vec<Vec<String>>,
}

impl CsvTable {
    fn parse(input: &str) -> Result<Self, String> {
        let mut lines = input.lines();
        let header_line = lines.next().ok_or("Empty CSV".to_string())?;
        let headers: Vec<String> = header_line.split(',').map(|s| s.trim().to_string()).collect();
        let num_cols = headers.len();

        let mut rows = Vec::new();
        for line in lines {
            let row: Vec<String> = line.split(',').map(|s| s.trim().to_string()).collect();
            if row.len() != num_cols {
                return Err(format!("Row has {} columns, expected {}", row.len(), num_cols));
            }
            rows.push(row);
        }

        Ok(CsvTable { headers, rows })
    }

    fn column_index(&self, column: &str) -> Option<usize> {
        self.headers.iter().position(|h| h == column)
    }

    fn filter(&self, column: &str, predicate: impl Fn(&str) -> bool) -> CsvTable {
        let col_idx = match self.column_index(column) {
            Some(idx) => idx,
            None => return self.clone(),
        };

        let rows = self.rows.iter()
            .filter(|row| predicate(&row[col_idx]))
            .cloned()
            .collect();

        CsvTable {
            headers: self.headers.clone(),
            rows,
        }
    }

    fn sort_by(&self, column: &str, numeric: bool) -> CsvTable {
        let col_idx = match self.column_index(column) {
            Some(idx) => idx,
            None => return self.clone(),
        };

        let mut rows = self.rows.clone();
        if numeric {
            rows.sort_by(|a, b| {
                let a_val: f64 = a[col_idx].parse().unwrap_or(0.0);
                let b_val: f64 = b[col_idx].parse().unwrap_or(0.0);
                b_val.partial_cmp(&a_val).unwrap_or(std::cmp::Ordering::Equal)
            });
        } else {
            rows.sort_by(|a, b| a[col_idx].cmp(&b[col_idx]));
        }

        CsvTable {
            headers: self.headers.clone(),
            rows,
        }
    }

    fn column_stats(&self, column: &str) -> Result<(f64, f64, f64, f64), String> {
        let col_idx = self.column_index(column)
            .ok_or_else(|| format!("Column '{}' not found", column))?;

        let values: Vec<f64> = self.rows.iter()
            .filter_map(|row| row[col_idx].parse::<f64>().ok())
            .collect();

        if values.is_empty() {
            return Err("No numeric values in column".to_string());
        }

        let sum: f64 = values.iter().sum();
        let avg = sum / values.len() as f64;
        let min = values.iter().cloned().fold(f64::INFINITY, f64::min);
        let max = values.iter().cloned().fold(f64::NEG_INFINITY, f64::max);

        Ok((sum, avg, min, max))
    }

    fn display(&self) {
        let mut widths: Vec<usize> = self.headers.iter().map(|h| h.len()).collect();
        for row in &self.rows {
            for (i, cell) in row.iter().enumerate() {
                if cell.len() > widths[i] {
                    widths[i] = cell.len();
                }
            }
        }

        let header_line: Vec<String> = self.headers.iter().enumerate()
            .map(|(i, h)| format!("{:width$}", h, width = widths[i]))
            .collect();
        println!("{}", header_line.join(" | "));
        println!("{}", widths.iter().map(|w| "-".repeat(*w)).collect::<Vec<_>>().join("-+-"));

        for row in &self.rows {
            let cells: Vec<String> = row.iter().enumerate()
                .map(|(i, c)| format!("{:width$}", c, width = widths[i]))
                .collect();
            println!("{}", cells.join(" | "));
        }
    }
}

fn main() {
    let csv = "name,age,score\nAlice,30,95\nBob,25,87\nCharlie,35,92\nDiana,28,98";

    let table = CsvTable::parse(csv).unwrap();
    table.display();

    println!("\nFiltered (age > 28):");
    let filtered = table.filter("age", |v| v.parse::<i32>().map_or(false, |n| n > 28));
    filtered.display();

    println!("\nSorted by score (descending):");
    let sorted = table.sort_by("score", true);
    sorted.display();

    if let Ok((sum, avg, min, max)) = table.column_stats("score") {
        println!("\nScore stats: sum={}, avg={:.1}, min={}, max={}", sum, avg, min, max);
    }
}
